-- Real exam questions for all 16 courses (10 questions each)

SET FOREIGN_KEY_CHECKS=0;
TRUNCATE TABLE lms_exam_questions;
SET FOREIGN_KEY_CHECKS=1;


-- Update total_questions count on each exam
UPDATE `lms_exams` SET `total_questions`=10, `total_marks`=10 WHERE `course_id`=1 AND `id`=(SELECT id FROM (SELECT id FROM lms_exams WHERE course_id=1 AND is_published=1 ORDER BY created_at DESC LIMIT 1) t);
